20‚Üí
21‚Üí  const fetchData = async () => {
22‚Üí    try {
23‚Üí      const [opsRes, asgRes, restRes] = await Promise.all([
24‚Üí        fetch(`${API}/operators`, { headers }),
25‚Üí        fetch(`${API}/assignments`, { headers }),
26‚Üí        fetch(`${API}/rest-days/today`, { headers }),
27‚Üí      ]);
