33‚Üí
34‚Üí  useEffect(() => { fetchData(); }, []);
35‚Üí  useEffect(() => { const h = () => fetchData(); window.addEventListener('app-refresh', h); return () => window.removeEventListener('app-refresh', h); }, []);
