69‚Üí      fetchData();
70‚Üí      emitRefresh();
71‚Üí    } catch (e) {}
72‚Üí  };
73‚Üí
74‚Üí  const toggleMachine = (id) => {
75‚Üí    setSelectedMachines(prev =>
76‚Üí      prev.includes(id) ? prev.filter(m => m !== id) : [...prev, id]
77‚Üí    );
78‚Üí  };
79‚Üí
80‚Üí  const handleAssign = async () => {
81‚Üí    if (!selectedOperator || selectedMachines.length === 0) return;
